  ('social-worker-moex-04550', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '區域性「社會福利服務中心」強調以家庭為核心、社區為基礎。社會工
作者每天面對不同類型的案主，提供不同的服務項目。試問社會福利服
務中心社會工作者可以扮演那些綜融性社會工作角色？社會工作者需
具備那些核心能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04551', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作方法從 20 世紀初期開始有系統整理、逐步發展，關於社會工作方法發展敘述下列何者 錯誤？', '["打破工作方法分立的綜融（genericpractice）實施，訓練社會工作者為通才，不注重專精實施領 域的知識、技巧", "1930-1945年間個案工作快速發展，此階段案主已不被認為是行為偏差的人，而是需要特別協 助的人，人在情境中（personinthesituation）是評估的核心概念", "社區組織是最後被專業社群納入的工作方法", "睦鄰運動使用以休閒活動為基礎的團體，運用團體自助的本質支持都市移民，當時團體工作尚 未納入社會工作訓練課程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04552', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '1942年的《貝弗里奇報告書》勾勒出戰後英國福利國家的藍圖，主要政策內容不包括下列何者？', '["兒童津貼", "全面性健康與復健服務", "維持就業", "社會住宅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04553', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '1935 年美國「社會安全法案」，為美國建立劃時代的社會安全制度，其主要內容有三個方案，不 包括下列何項內容？', '["社會保險", "社會住宅", "公共救助", "衛生及福利服務方案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04554', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作是一門助人專業，下列有關社會工作「醫療模式」到「結構變遷」之敘述，何者正確？', '["醫療模式強調個人取向的介入", "基變模式屬於結構變遷取向，因此個人取向不會有基變模式 的特性", "馬克思主義社會工作屬於結構變遷取向的社會工作內涵", "Jane Adams 是醫療模式社 會工作的提倡者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04555', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'HarrietBartlett（1970）認為社會工作的核心是協助人們解決生命難題及平衡環境的要求。根據這 樣的核心概念，下列所描述的社會工作基本價值何者錯誤？', '["社會工作重視社會責任", "社會工作強調案主的適者生存能力", "社會工作尊重案主的獨特性", "社會工作協助案主朝向自我實現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04556', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的專業發展有其特殊性，構成與其他專業之區別。下列敘述之社會工作特性何者錯誤？', '["Gilbelman（1990）認為社會工作與其他專業的最大區別，社會工作的協助焦點兼顧個人與環 境，以及二者間之互動", "社會工作運用社區資源協助案主解決問題和滿足需求", "大多數社會工作者從事個人的心理治療工作", "社會工作者能有效地統籌和運用團隊提供專業服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04557', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當社會工作者在服務歷程中察覺人口老化的趨勢，並敏感到社會問題警訊，甚至試圖開啟長期照 顧制度的規劃，此時社會工作者的角色應可視為下列何者？', '["協調者", "教育者", "發動者", "充權者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04558', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在調整服務方法運用上，綜融取向的社會工作主要考量因素為何？', '["以專家為中心", "助人情境的差異", "社會工作者自身專長", "機構屬性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04559', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學者Gambrill,E.和Gibbs,L.認為社會工作者需將批判性思考整合證據作為實務工作之基礎。批判 性思考具有之特質，下列何者錯誤？', '["由知識所引導，也回應知識", "關注思考要素與問題之間的邏輯關連", "堅持合理的解答", "實務工作的重要基礎是運用主觀判斷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
